var prompt = 'You are a scheduling assistant. Parse and validate the following appointment request.

';
prompt += 'PATIENT: ' + $.input.patientName + '
';
prompt += 'EMAIL: ' + $.input.patientEmail + '
';
prompt += 'REQUESTED DATE: ' + $.input.requestedDate + '
';
prompt += 'REQUESTED TIME: ' + ($.input.requestedTime || 'morning') + '
';
prompt += 'TYPE: ' + ($.input.appointmentType || 'General Consultation') + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Parse the date into ISO format (YYYY-MM-DD)
';
prompt += '- Convert time preference to specific time slots (30-min intervals, 9am-5pm)
';
prompt += '- Suggest 3 alternative time slots
';
prompt += '- Generate a professional confirmation email body in HTML
';
prompt += '- Estimate appointment duration based on type

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "parsedDate": "YYYY-MM-DD",
';
prompt += '  "parsedTime": "HH:MM",
';
prompt += '  "duration": "30 min|60 min|90 min",
';
prompt += '  "alternatives": [{ "date": "YYYY-MM-DD", "time": "HH:MM" }],
';
prompt += '  "confirmationSubject": "Email subject line",
';
prompt += '  "confirmationBody": "HTML email body with appointment details",
';
prompt += '  "sheetEntry": {
';
prompt += '    "Date": "YYYY-MM-DD",
';
prompt += '    "Time": "HH:MM",
';
prompt += '    "PatientName": "...",
';
prompt += '    "Email": "...",
';
prompt += '    "AppointmentType": "...",
';
prompt += '    "Duration": "...",
';
prompt += '    "Status": "Confirmed"
';
prompt += '  }
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiSchedule.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) {
  var today = new Date();
  today.setDate(today.getDate() + 1);
  var dateStr = today.toISOString().split('T')[0];
  return { parsedDate: dateStr, parsedTime: '10:00', duration: '30 min', alternatives: [], confirmationSubject: 'Appointment Confirmation', confirmationBody: '<p>Your appointment has been confirmed.</p>', sheetEntry: { Date: dateStr, Time: '10:00', PatientName: $.input.patientName, Email: $.input.patientEmail, AppointmentType: $.input.appointmentType || 'General Consultation', Duration: '30 min', Status: 'Confirmed' } };
}
